INSERT INTO public.document_templates (id, name_ru, name_kk, category, description, file_format, status, schema, default_workflow_id, allow_custom_route) VALUES ('c1b2c3d4-e5f6-4789-a012-000000000201', 'Входящий документ', 'Кіріс құжаты', 'incoming', 'Регистрационная карточка входящей корреспонденции', 'html', 'published', '{"title_template_ru":"Вх. № {{external_reg_number}} — {{document_subject}}","title_template_kk":"Кіріс № {{external_reg_number}} — {{document_subject}}","fields":[{"key":"organization_name","label_ru":"Организация","label_kk":"Ұйым","type":"text","required":true,"source":"organization"},{"key":"correspondent_name","label_ru":"Контрагент","label_kk":"Контрагент","type":"text","required":true},{"key":"external_reg_number","label_ru":"Вх. № контрагента","label_kk":"Контрагент кіріс нөмірі","type":"text","required":true},{"key":"received_date","label_ru":"Дата поступления","label_kk":"Түскен күні","type":"date","required":true},{"key":"document_subject","label_ru":"Тема","label_kk":"Тақырып","type":"text","required":true},{"key":"document_summary","label_ru":"Краткое содержание","label_kk":"Қысқаша мазмұны","type":"textarea","required":true},{"key":"executor_name","label_ru":"Исполнитель","label_kk":"Орындаушы","type":"text","required":false,"source":"author"},{"key":"executor_position","label_ru":"Должность исполнителя","label_kk":"Орындаушы лауазымы","type":"text","required":false,"source":"author"},{"key":"resolution","label_ru":"Резолюция / поручение","label_kk":"Резолюция / тапсырма","type":"textarea","required":false},{"key":"attachments","label_ru":"Приложения","label_kk":"Қосымшалар","type":"textarea","required":false}],"body_template":"{{organization_name}}\n\nВХОДЯЩИЙ ДОКУМЕНТ\n\nВх. № {{external_reg_number}} от {{correspondent_name}}\nДата поступления: {{received_date}}\n\nТема: {{document_subject}}\n\nКраткое содержание:\n{{document_summary}}\n\nИсполнитель: {{executor_name}}, {{executor_position}}\nРезолюция / поручение:\n{{resolution}}\n\nПриложение: {{attachments}}"}'::jsonb, 'b1b2c3d4-e5f6-4789-a012-000000000101', true)
