INSERT INTO public.document_templates (id, name_ru, name_kk, category, description, file_format, status, schema, default_workflow_id, allow_custom_route) VALUES ('c1b2c3d4-e5f6-4789-a012-000000000202', 'Исходящее письмо', 'Шығыс хат', 'outgoing', 'Стандартное исходящее письмо контрагенту', 'html', 'published', '{"title_template_ru":"Исх. письмо: {{document_subject}}","title_template_kk":"Шығыс хат: {{document_subject}}","fields":[{"key":"organization_name","label_ru":"Организация","label_kk":"Ұйым","type":"text","required":true,"source":"organization"},{"key":"correspondent_name","label_ru":"Контрагент","label_kk":"Контрагент","type":"text","required":true},{"key":"correspondent_address","label_ru":"Адрес контрагента","label_kk":"Контрагент мекенжайы","type":"textarea","required":false},{"key":"correspondent_contact","label_ru":"Кому (обращение)","label_kk":"Кімге","type":"text","required":true},{"key":"document_number","label_ru":"Номер документа","label_kk":"Құжат нөмірі","type":"text","required":true,"source":"system"},{"key":"document_date","label_ru":"Дата документа","label_kk":"Құжат күні","type":"date","required":true,"source":"system"},{"key":"document_subject","label_ru":"Тема","label_kk":"Тақырып","type":"text","required":true},{"key":"document_body","label_ru":"Текст","label_kk":"Мәтін","type":"textarea","required":true},{"key":"signer_position","label_ru":"Должность подписанта","label_kk":"Қол қоюшы лауазымы","type":"text","required":true,"source":"signatory"},{"key":"signer_name","label_ru":"ФИО подписанта","label_kk":"Қол қоюшы аты-жөні","type":"text","required":true,"source":"signatory"},{"key":"executor_name","label_ru":"Исполнитель","label_kk":"Орындаушы","type":"text","required":false,"source":"author"},{"key":"executor_phone","label_ru":"Телефон исполнителя","label_kk":"Орындаушы телефоны","type":"text","required":false,"source":"author"},{"key":"attachments","label_ru":"Приложения","label_kk":"Қосымшалар","type":"textarea","required":false}],"body_template":"{{organization_name}}\n\n{{correspondent_name}}\n{{correspondent_address}}\n\nИсх. № {{document_number}}\nот {{document_date}}\n\n{{document_subject}}\n\nУважаемый(ая) {{correspondent_contact}}!\n\n{{document_body}}\n\nПриложение: {{attachments}}\n\nС уважением,\n{{signer_position}}\n_______________ /{{signer_name}}/\n\nИсп.: {{executor_name}}, тел. {{executor_phone}}"}'::jsonb, 'b1b2c3d4-e5f6-4789-a012-000000000102', true)
