INSERT INTO public.document_templates (id, name_ru, name_kk, category, description, file_format, status, schema, default_workflow_id, allow_custom_route) VALUES ('c1b2c3d4-e5f6-4789-a012-000000000205', 'Договор', 'Шарт', 'contract', 'Типовой договор с контрагентом', 'html', 'published', '{"title_template_ru":"Договор № {{contract_number}} — {{correspondent_name}}","title_template_kk":"Шарт № {{contract_number}} — {{correspondent_name}}","fields":[{"key":"organization_name","label_ru":"Организация","label_kk":"Ұйым","type":"text","required":true,"source":"organization"},{"key":"contract_number","label_ru":"Номер договора","label_kk":"Шарт нөмірі","type":"text","required":true},{"key":"contract_date","label_ru":"Дата договора","label_kk":"Шарт күні","type":"date","required":true},{"key":"contract_city","label_ru":"Место заключения","label_kk":"Жасалған жері","type":"text","required":false},{"key":"correspondent_name","label_ru":"Контрагент","label_kk":"Контрагент","type":"text","required":true},{"key":"correspondent_representative","label_ru":"Представитель контрагента","label_kk":"Контрагент өкілі","type":"text","required":true},{"key":"contract_subject","label_ru":"Предмет договора","label_kk":"Шарт пәні","type":"textarea","required":true},{"key":"contract_amount","label_ru":"Сумма","label_kk":"Сома","type":"text","required":true},{"key":"contract_term","label_ru":"Срок действия","label_kk":"Мерзімі","type":"text","required":true},{"key":"contract_body","label_ru":"Условия","label_kk":"Шарттар","type":"textarea","required":true},{"key":"contract_closing","label_ru":"Заключительные положения","label_kk":"Қорытынды","type":"textarea","required":false},{"key":"signer_position","label_ru":"Должность подписанта","label_kk":"Қол қоюшы лауазымы","type":"text","required":true,"source":"signatory"},{"key":"signer_name","label_ru":"ФИО подписанта","label_kk":"Қол қоюшы аты-жөні","type":"text","required":true,"source":"signatory"}],"body_template":"{{organization_name}}\n\nДОГОВОР № {{contract_number}}\n\nг. {{contract_city}}                                    {{contract_date}}\n\n{{organization_name}}, именуемое в дальнейшем «Заказчик», в лице {{signer_position}} {{signer_name}},\nс одной стороны, и {{correspondent_name}}, именуемое в дальнейшем «Исполнитель», в лице {{correspondent_representative}},\nс другой стороны, заключили настоящий договор о нижеследующем:\n\n1. ПРЕДМЕТ ДОГОВОРА\n{{contract_subject}}\n\n2. СТОИМОСТЬ И ПОРЯДОК РАСЧЁТОВ\nСумма договора: {{contract_amount}} тенге.\nСрок действия: {{contract_term}}.\n\n3. ПРАВА И ОБЯЗАННОСТИ СТОРОН\n{{contract_body}}\n\n4. ЗАКЛЮЧИТЕЛЬНЫЕ ПОЛОЖЕНИЯ\n{{contract_closing}}\n\nЗаказчик: _______________ /{{signer_name}}/\nИсполнитель: _______________ /{{correspondent_representative}}/"}'::jsonb, 'b1b2c3d4-e5f6-4789-a012-000000000105', true)
