INSERT INTO public.document_templates (id, name_ru, name_kk, category, description, file_format, status, schema, default_workflow_id, allow_custom_route) VALUES ('c1b2c3d4-e5f6-4789-a012-000000000208', 'Акт', 'Акт', 'act', 'Акт выполненных работ / приёмки-передачи', 'html', 'published', '{"title_template_ru":"Акт № {{act_number}} — {{act_subject}}","title_template_kk":"Акт № {{act_number}} — {{act_subject}}","fields":[{"key":"organization_name","label_ru":"Организация","label_kk":"Ұйым","type":"text","required":true,"source":"organization"},{"key":"act_number","label_ru":"Номер акта","label_kk":"Акт нөмірі","type":"text","required":true},{"key":"act_date","label_ru":"Дата","label_kk":"Күні","type":"date","required":true},{"key":"act_subject","label_ru":"Предмет акта","label_kk":"Акт пәні","type":"text","required":true},{"key":"act_basis","label_ru":"Основание","label_kk":"Негіз","type":"text","required":true},{"key":"correspondent_name","label_ru":"Контрагент","label_kk":"Контрагент","type":"text","required":true},{"key":"party_a","label_ru":"Представитель заказчика","label_kk":"Тапсырыс беруші","type":"text","required":true},{"key":"party_b","label_ru":"Представитель исполнителя","label_kk":"Орындаушы","type":"text","required":true},{"key":"act_body","label_ru":"Содержание акта","label_kk":"Акт мазмұны","type":"textarea","required":true}],"body_template":"{{organization_name}}\n\nАКТ № {{act_number}}\n\n{{act_date}}\n\n{{act_subject}}\n\nОснование: {{act_basis}}\n\n{{organization_name}} ({{party_a}}) и {{correspondent_name}} ({{party_b}}) составили настоящий акт о нижеследующем:\n\n{{act_body}}\n\nСтороны претензий друг к другу не имеют.\n\nОт Заказчика: _______________ /{{party_a}}/\nОт Исполнителя: _______________ /{{party_b}}/"}'::jsonb, 'b1b2c3d4-e5f6-4789-a012-000000000108', true)
